class TestGetBraintrustConfig:
    """get_braintrust_config reads environment variables and exposes an 'enabled' flag."""

    def test_enabled_defaults_to_true_when_env_unset(self):
        """BRAINTRUST_LOGGING_ENABLED absent → enabled=True."""
        with patch.dict("os.environ", {}, clear=False):
            # Remove the key if it happens to be present in the test environment
            import os

            os.environ.pop("BRAINTRUST_LOGGING_ENABLED", None)

            from chat.V2.utils import get_braintrust_config

            config = get_braintrust_config()

        assert config.enabled is True

    def test_enabled_is_true_when_set_to_true(self):
        """BRAINTRUST_LOGGING_ENABLED=true → enabled=True."""
        with patch.dict("os.environ", {"BRAINTRUST_LOGGING_ENABLED": "true"}):
            from chat.V2.utils import get_braintrust_config

            config = get_braintrust_config()

        assert config.enabled is True

    @pytest.mark.parametrize("value", ["false", "False", "FALSE"])
    def test_enabled_is_false_when_set_to_false(self, value):
        """BRAINTRUST_LOGGING_ENABLED=false (any case) → enabled=False."""
        with patch.dict("os.environ", {"BRAINTRUST_LOGGING_ENABLED": value}):
            from chat.V2.utils import get_braintrust_config

            config = get_braintrust_config()

        assert config.enabled is False

    def test_api_key_and_project_are_read_from_env(self):
        """api_key and project fields are populated from environment variables."""
        env = {
            "BRAINTRUST_API_KEY": "test-bt-key-xyz",
            "BRAINTRUST_PROJECT": "MyProject",
            "BRAINTRUST_LOGGING_ENABLED": "true",
        }
        with patch.dict("os.environ", env):
            from chat.V2.utils import get_braintrust_config

            config = get_braintrust_config()

        assert config.api_key == "test-bt-key-xyz"
        assert config.project == "MyProject"

    def test_project_defaults_when_env_unset(self):
        """BRAINTRUST_PROJECT absent → falls back to 'On Site Agent'."""
        import os

        with patch.dict("os.environ", {}, clear=False):
            os.environ.pop("BRAINTRUST_PROJECT", None)

            from chat.V2.utils import get_braintrust_config

            config = get_braintrust_config()

        assert config.project == "On Site Agent"


