class TestSetupBraintrustTracingDisabled:
    """When Braintrust logging is disabled, _setup_braintrust_tracing is a no-op."""

    def test_no_sdk_setup_when_logging_disabled(self):
        """setup_claude_agent_sdk must NOT be called when braintrust_logging_enabled=False."""
        mock_setup = MagicMock()

        with patch.dict(
            "os.environ",
            {
                "BRAINTRUST_API_KEY": "key",
                "BRAINTRUST_LOGGING_ENABLED": "false",
                "ANTHROPIC_API_KEY": "ant-key",
            },
        ):
            with patch(
                "chat.V2.agent.claude_service.setup_claude_agent_sdk", mock_setup
            ):
                from chat.V2.agent import claude_service

                # Reset so a fresh instance triggers setup path
                claude_service._BRAINTRUST_SETUP_DONE = False

                with (
                    patch.object(claude_service, "ClaudeAgentOptions", MagicMock()),
                    patch.object(claude_service, "ClaudeSDKClient", MagicMock()),
                    patch.object(claude_service, "create_sdk_mcp_server", MagicMock()),
                    patch.object(claude_service, "tool", MagicMock()),
                ):
                    try:
                        service = claude_service.ClaudeAgentService()
                        assert service.braintrust_logging_enabled is False
                    except RuntimeError:
                        pytest.skip("claude-agent-sdk not installed")

        mock_setup.assert_not_called()

